const toVNTime = (d = new Date()) => {
  const date = new Date(d.getTime() + 7 * 60 * 60 * 1000); // UTC+7
  return date;
};

const formatDate = (date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, "0");
  const d = String(date.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
};

const formatDayMonth = (date) => {
  const d = String(date.getDate()).padStart(2, "0");
  const m = String(date.getMonth() + 1).padStart(2, "0");
  return `${d}/${m}`;
};

const getDayOfWeek = (date) => {
  const days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];
  return days[date.getDay()];
};

const titleSheet = (date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, "0");
  return `${y}-${m}`;
};

const now = toVNTime();

const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);

const twoDaysAgo = new Date(now);
twoDaysAgo.setDate(twoDaysAgo.getDate() - 2);

const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);

// ===== Last week (Monday → Sunday) =====
const today = new Date(now);
const dayIndex = (today.getDay() + 6) % 7; // Monday = 0
const todayStr = formatDate(now);
const [year, month, day] = (todayStr.split("-"));
const startOfLastWeek = new Date(today);
startOfLastWeek.setDate(today.getDate() - dayIndex - 7);

const endOfLastWeek = new Date(startOfLastWeek);
endOfLastWeek.setDate(startOfLastWeek.getDate() + 6);

// ===== Current week (DD/MM) =====
const startOfWeek = new Date(today);
startOfWeek.setDate(today.getDate() - dayIndex);

const endOfWeek = new Date(startOfWeek);
endOfWeek.setDate(startOfWeek.getDate() + 6);


return [{
  today: formatDate(now),
  yesterday: formatDate(yesterday),
  twoDaysAgo: formatDate(twoDaysAgo),
  tomorrow: formatDate(tomorrow),

  dayOfWeekYesterday: getDayOfWeek(yesterday),
  monthYesterday: titleSheet(yesterday),

  startOfLastWeek: formatDate(startOfLastWeek),
  endOfLastWeek: formatDate(endOfLastWeek),

  startOfLastWeekDM: formatDayMonth(startOfLastWeek),
  endOfLastWeekDM: formatDayMonth(endOfLastWeek),

  reportYearFolder: `${year}-Report`,
  reportDateFolder: `${year}${month}${day}-Report`,
}];

const odoo_Calendar_Event_Sheet = $items("Step 8: Read the Odoo Calendar Event notifications that have been sent.");
const records = $items("Step 6: Filter out events whose titles match the action of a customer visiting the company.");

const sentEventIds = new Set(
  odoo_Calendar_Event_Sheet
    .filter(item => item.json["The day before"] === "Sent")
    .map(item => item.json.ID)
);

function formatDateTime(dateTimeStr) {
  if (!dateTimeStr) return null;

  return dateTimeStr
    .replace("T", " ")
    .replace(/\+\d{2}:\d{2}$/, "");
}

const result = records
  .map(item => {
    const name = item.json.summary.replace(/\[.*?\]\s*/g, '');

    return {
      odoo_calendar_event_id: item.json.id,
      odoo_calendar_event_name: name,
      odoo_calendar_event_start: formatDateTime(item.json.start.dateTime),
      odoo_calendar_event_stop: formatDateTime(item.json.end.dateTime),
      attendees: item.json.attendees,
    };
  })
  .filter(item => !sentEventIds.has(item.odoo_calendar_event_id));

return result;

const attendee_ids = $node["Step 12: Loop Over Items"].json.attendees;
const mergedResults = $items("Step 9: Read Google Sheets member slack");
const odoo_calendar_event_name = $('Step 12: Loop Over Items').first().json.odoo_calendar_event_name;
const odoo_calendar_event_start = $('Step 12: Loop Over Items').first().json.odoo_calendar_event_start;
const odoo_calendar_event_stop = $('Step 12: Loop Over Items').first().json.odoo_calendar_event_stop;

const finalResult = [];

for (const item of attendee_ids) {
  const inputEmail = String(item.email || "").toLowerCase().trim();
  if (!inputEmail) continue;

  const inputLocal = inputEmail.split("@")[0];

  let bestMatch = null;
  let bestScore = -1;

  for (const sheetItem of mergedResults) {
    const data = sheetItem.json || {};
    if (!data.Email) continue;

    const itemEmail = String(data.Email).toLowerCase().trim();
    const itemLocal = itemEmail.split("@")[0];

    let score = 0;

    if (itemEmail === inputEmail) score = 100;
    else if (itemLocal === inputLocal) score = 80;
    else if (itemEmail.includes(inputLocal)) score = 50;

    if (score > bestScore) {
      bestScore = score;
      bestMatch = data;
    }
  }

  if (bestMatch && bestScore >= 50) {
    finalResult.push({
      email: inputEmail,
      memberID: bestMatch.memberID,
      odoo_calendar_event_name,
      odoo_calendar_event_start,
      odoo_calendar_event_stop
    });
  }
}

return finalResult;

